VALUES
  ('social-worker-moex-05980', 'social-worker', 'social-worker-moex-105-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '有關社會保險財務處理方式，採取「隨收隨付制」的敘述，下列何者錯誤？', '["此種財務處理方式，無需提存準備，充其量僅需提存少量的準備金即可", "此種財務處理方式通常見於健康保險等短期性社會保險", "此種財務處理方式只要對於給付水準或保險費率進行調整就可以維持收支平衡", "此種財務處理方式在所得重分配效果上較不明顯"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "8e1229169756", "answer_pdf_sha1": "32de1633409b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05981', 'social-worker', 'social-worker-moex-105-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依據兒童及少年性剝削防制條例規定，下列敘述何者錯誤？', '["直轄市、縣（市）主管機關得令被害人之父母、監護人或其他實際照顧之人接受八小時以上四十小時 以下之親職教育輔導，並得實施家庭處遇計畫", "被害人經安置後，主管機關應每三個月進行評估", "直轄市、縣（市）主管機關應於被害人安置後四十五日內，向法院提出審前報告，並聲請法院裁定", "檢察官或司法警察官查獲及救援被害人後，應於二十四小時內將被害人交由當地直轄市、縣（市）主 管機關處理"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "8e1229169756", "answer_pdf_sha1": "32de1633409b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05982', 'social-worker', 'social-worker-moex-105-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依據兒童及少年福利與權益保障法有關停車位的規定，下列敘述何者正確？', '["所有公共停車場均應保留百分之二之汽車停車位，作為孕婦、育有六歲以下兒童者之停車位", "汽車停車位已滿五十個之公共停車場，至少應保留一個孕婦、育有六歲以下兒童者之停車位", "營業場所總樓地板面積五千平方公尺以上之百貨公司，應設有孕婦、育有六歲以下兒童者之停車位", "汽車停車位未滿二十五個之公共停車場，不受須設置孕婦、育有六歲以下兒童者之停車位的限制"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "8e1229169756", "answer_pdf_sha1": "32de1633409b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05983', 'social-worker', 'social-worker-moex-105-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依據身心障礙者權益保障法有關身心障礙證明之效期及核發規定，下列敘述何者正確？', '["身心障礙證明有效期限最長為六年", "身心障礙者應於效期屆滿前九十日內向戶籍所在地之直轄市、縣（市）主管機關申請辦理重新鑑定及 需求評估", "身心障礙者於其證明效期屆滿前九十日尚未申請辦理重新鑑定及需求評估者，地方主管機關應以書面 通知其辦理", "地方主管機關發現身心障礙者障礙情況改變時，得以書面通知其於九十日內辦理重新鑑定與需求評估"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "8e1229169756", "answer_pdf_sha1": "32de1633409b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05984', 'social-worker', 'social-worker-moex-105-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依據長期照顧服務法有關家庭照顧者支持服務提供之項目，下列何種組合正確？①家屬教育服務  ②長', '["喘息服務", "社會參與服務  ⑤情緒支持及團體服務之轉介", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "8e1229169756", "answer_pdf_sha1": "32de1633409b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 33, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05985', 'social-worker', 'social-worker-moex-105-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '世界銀行將老人經濟生活保障，由原來三柱模式擴大為五柱模式，有關五柱模式的內涵，下列敘述何者 正確？', '["第零柱指的是基於倫理規範，由家庭成員為老年提供生活照顧", "第一柱指的是採取社會救助方式，實施資產調查及排富條款", "第二柱指的是強制性保障制度，透過社會保險年金制度，產生社會連帶", "第三柱指的是自願性的個人商業保險儲蓄制度，主要經營者是私人機構"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "8e1229169756", "answer_pdf_sha1": "32de1633409b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05986', 'social-worker', 'social-worker-moex-105-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '有關性別主流化的敘述，下列何者錯誤？', '["成功的性別主流化需有多元的觀點，才能使性別平等在整個過程和介入期間，有系統的成為主流", "對於婦女不平等的處境放在更寬廣的「性別關係」議題架構下來審視與行動", "是要將性別觀點帶入公共事務中，成為從規劃到執行均需具備的主要元素", "對於婦女處境的策略出現典範移轉，從「發展中的婦女」轉變為「性別與發展」"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "8e1229169756", "answer_pdf_sha1": "32de1633409b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05987', 'social-worker', 'social-worker-moex-105-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依據家庭暴力防治法有關保護令的規定，下列敘述何者正確？', '["通常保護令之有效期間為一年以下，自核發時起生效", "通常保護令失效前，法院得依當事人或被害人之聲請撤銷、變更或延長之。延長保護令之聲請，每次 延長期間為一年以下", "法院核發暫時保護令或緊急保護令，應經審理程序", "法院為保護被害人，得於通常保護令審理終結前，依聲請或依職權核發暫時保護令"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "8e1229169756", "answer_pdf_sha1": "32de1633409b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05988', 'social-worker', 'social-worker-moex-105-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依據性侵害犯罪防治法有關教育及通報事項的規定，下列敘述何者正確？', '["村（里）長係屬本法所定義務通報人", "義務通報人知悉有疑似性侵害犯罪情事者，應立即向當地直轄市、縣（市）主管機關通報，至遲不得 超過二十四小時", "直轄市、縣（市）主管機關於知悉或接獲通報時，應立即進行分級分類處理，至遲不得超過十二小時", "各級中小學每學年應至少有八小時以上之性侵害防治教育課程"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "8e1229169756", "answer_pdf_sha1": "32de1633409b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05989', 'social-worker', 'social-worker-moex-105-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依據原住民族工作權保障法規定，下列敘述何者正確？', '["本法所稱主管機關：在中央為行政院原住民委員會", "各級政府機關、公立學校及公營事業機構，其僱用所有人員之總額，每滿一百人應有原住民一人", "各級政府機關、公立學校及公營事業機構，應僱用原住民之地區，排除澎湖、金門、連江縣", "原住民地區之各級政府機關、公立學校及公營事業機構，其僱用所有人員之總額，應有三分之一以上 為原住民"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "8e1229169756", "answer_pdf_sha1": "32de1633409b", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
